    canonical_messages = consolidate_messages(messages or [])
    batches: List[List[Dict[str, Any]]] = []
    current_batch: List[Dict[str, Any]] = []

    for msg in canonical_messages:
        role = msg.get("role")
        if role == "system":
            continue
        if role == "user":
            if current_batch:
                batches.append(current_batch)
                current_batch = []
            batches.append([msg])
            continue
        current_batch.append(msg)

    if current_batch:
        batches.append(current_batch)
    return batches


